"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import type { ColumnDef, RowSelectionState } from "@tanstack/react-table";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";
import { Badge } from "@ui/components/badge";
import { Button } from "@ui/components/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@ui/components/dialog";
import { Input } from "@ui/components/input";
import { Label } from "@ui/components/label";
import { PageSection } from "@ui/components/layout";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@ui/components/tabs";
import { TypographyH1, TypographyH2 } from "@ui/components/typography";
import {
  AlertCircle,
  ArchiveRestore,
  Hash,
  Pencil,
  Plus,
  RefreshCw,
  Trash2,
} from "lucide-react";
import { AdminDataTable } from "@/components/admin-data-table";
import { AdminTablePaginationFooter } from "@/components/admin-table-pagination-footer";
import { AdminConfirmActionDialog } from "@/components/admin-confirm-action-dialog";
import { AdminPageGuard } from "@/components/admin-page-guard";
import { api } from "@/lib/api";
import { useDebouncedValue } from "@/hooks/use-debounced-value";
import { useAuth } from "@/providers/auth-provider";
import { canUserAccess, PERMISSION_CODES } from "@workspace/api-client";
import {
  ADMIN_ALERT_DIALOG_CONTENT_CLASS,
  ADMIN_DIALOG_CONTENT_CATEGORY_CLASS,
  ADMIN_PAGE_SUBTITLE_CLASS,
  ADMIN_PAGE_TITLE_ICON_CLASS,
  ADMIN_PAGE_TITLE_PRIMARY_CLASS,
} from "@ui/lib/layout-shell";

type TagRow = {
  id: string;
  name: string;
  slug: string;
  createdAt: string;
  updatedAt: string;
  deletedAt: string | null;
};

type TagTreeRow = TagRow & {
  isGroup?: boolean;
  itemCount?: number;
  subRows?: TagTreeRow[];
};

type PagedResult<T> = { items: T[]; total: number };
type ApiEnvelope<T> = { success?: boolean; message?: string; error?: string | null; data?: T };
type TagsApiShape = { data: TagRow[]; pagination?: { total?: number } };

type FormState = {
  id?: string;
  name: string;
  slug: string;
};

const EMPTY_FORM: FormState = {
  name: "",
  slug: "",
};

function slugify(input: string): string {
  return input
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/đ/g, "d")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
}

function unwrapEnvelope<T>(payload: unknown): T {
  if (!payload || typeof payload !== "object") return payload as T;
  const envelope = payload as ApiEnvelope<T>;
  if (envelope.success === false) {
    throw new Error(envelope.message || envelope.error || "Yeu cau that bai");
  }
  return "data" in envelope ? (envelope.data as T) : (payload as T);
}

function normalizePaged(payload: unknown): PagedResult<TagRow> {
  const data = unwrapEnvelope<TagsApiShape | TagRow[]>(payload);
  if (Array.isArray(data)) return { items: data, total: data.length };
  if (data && typeof data === "object" && Array.isArray(data.data)) {
    return {
      items: data.data,
      total:
        typeof data.pagination?.total === "number"
          ? data.pagination.total
          : data.data.length,
    };
  }
  return { items: [], total: 0 };
}

function formatDateTime(value: string | null | undefined): string {
  if (!value) return "—";
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? "—" : date.toLocaleString("vi-VN");
}

function humanizeSlug(slug: string): string {
  return slug
    .split("-")
    .filter(Boolean)
    .join(" ");
}

function sortTagsByName<T extends Pick<TagRow, "name">>(rows: T[]): T[] {
  return [...rows].sort((a, b) => a.name.localeCompare(b.name, "vi"));
}

function chooseTagGroupSlug(
  row: TagRow,
  prefixCounts: Map<string, number>,
): string | null {
  const segments = row.slug.split("-").filter(Boolean);
  const maxPrefixLength = Math.min(3, segments.length - 1);

  for (let length = maxPrefixLength; length >= 2; length -= 1) {
    const prefix = segments.slice(0, length).join("-");
    if ((prefixCounts.get(prefix) ?? 0) >= 2) {
      return prefix;
    }
  }

  if (segments.length > 1) {
    const rootPrefix = segments[0] ?? "";
    if ((prefixCounts.get(rootPrefix) ?? 0) >= 3) {
      return rootPrefix;
    }
  }

  return null;
}

function buildTagTree(rows: TagRow[]): TagTreeRow[] {
  const prefixCounts = new Map<string, number>();

  for (const row of rows) {
    const segments = row.slug.split("-").filter(Boolean);
    const maxPrefixLength = Math.min(3, segments.length - 1);
    for (let length = 1; length <= maxPrefixLength; length += 1) {
      const prefix = segments.slice(0, length).join("-");
      prefixCounts.set(prefix, (prefixCounts.get(prefix) ?? 0) + 1);
    }
  }

  const grouped = new Map<string, TagRow[]>();
  const standalone: TagTreeRow[] = [];

  for (const row of rows) {
    const groupSlug = chooseTagGroupSlug(row, prefixCounts);
    if (!groupSlug) {
      standalone.push({ ...row });
      continue;
    }
    const bucket = grouped.get(groupSlug) ?? [];
    bucket.push(row);
    grouped.set(groupSlug, bucket);
  }

  const groupRows = Array.from(grouped.entries())
    .sort(([a], [b]) => humanizeSlug(a).localeCompare(humanizeSlug(b), "vi"))
    .map(([groupSlug, groupItems]) => ({
      id: `group:${groupSlug}`,
      name: humanizeSlug(groupSlug),
      slug: groupSlug,
      createdAt: "",
      updatedAt: "",
      deletedAt: null,
      isGroup: true,
      itemCount: groupItems.length,
      subRows: sortTagsByName(groupItems).map((item) => ({ ...item })),
    }));

  return [...groupRows, ...sortTagsByName(standalone)];
}

async function fetchAllActiveTags(): Promise<TagRow[]> {
  const limit = 100;
  const items: TagRow[] = [];
  let page = 1;
  let total = Number.POSITIVE_INFINITY;

  while (items.length < total) {
    const result = normalizePaged(
      await api.http.get("/admin/tags", {
        query: {
          page,
          limit,
          status: "active",
        },
      }),
    );
    items.push(...result.items);
    total = result.total;
    if (result.items.length === 0) break;
    page += 1;
  }

  return items;
}

function TagsPageInner() {
  const queryClient = useQueryClient();
  const { user: session } = useAuth();
  const canRead =
    session != null &&
    (canUserAccess(session, PERMISSION_CODES.TAGS_VIEW) ||
      canUserAccess(session, PERMISSION_CODES.TAGS_MANAGE));
  const canWrite =
    session != null &&
    (canUserAccess(session, PERMISSION_CODES.TAGS_UPDATE) ||
      canUserAccess(session, PERMISSION_CODES.TAGS_CREATE) ||
      canUserAccess(session, PERMISSION_CODES.TAGS_MANAGE));
  const canDelete =
    session != null &&
    (canUserAccess(session, PERMISSION_CODES.TAGS_DELETE) ||
      canUserAccess(session, PERMISSION_CODES.TAGS_MANAGE));
  const [mainTab, setMainTab] = useState<"list" | "trash">("list");
  const [globalFilter, setGlobalFilter] = useState("");
  const [trashPage, setTrashPage] = useState(1);
  const [trashPageSize, setTrashPageSize] = useState(15);
  const [trashGlobalFilter, setTrashGlobalFilter] = useState("");
  const [dialogOpen, setDialogOpen] = useState(false);
  const [form, setForm] = useState<FormState>(EMPTY_FORM);
  const [deleteTarget, setDeleteTarget] = useState<TagRow | null>(null);
  const [restoreTarget, setRestoreTarget] = useState<TagRow | null>(null);
  const [purgeTarget, setPurgeTarget] = useState<TagRow | null>(null);
  const [listTagSelection, setListTagSelection] = useState<RowSelectionState>({});
  const [trashTagSelection, setTrashTagSelection] = useState<RowSelectionState>({});
  const debouncedTrashQ = useDebouncedValue(trashGlobalFilter, 350);

  const listQuery = useQuery({
    queryKey: ["media", "tags", "tree"],
    queryFn: fetchAllActiveTags,
    enabled: canRead,
  });

  const trashQuery = useQuery({
    queryKey: ["media", "tags", "trash", trashPage, trashPageSize, debouncedTrashQ],
    enabled: canRead && mainTab === "trash",
    queryFn: async (): Promise<PagedResult<TagRow>> =>
      normalizePaged(
        await api.http.get("/admin/tags", {
          query: {
            page: trashPage,
            limit: trashPageSize,
            search: debouncedTrashQ.trim() || undefined,
            status: "deleted",
          },
        }),
      ),
  });

  const reload = useCallback(async () => {
    await Promise.all([listQuery.refetch(), trashQuery.refetch()]);
  }, [listQuery, trashQuery]);

  const invalidateAll = useCallback(async () => {
    await queryClient.invalidateQueries({ queryKey: ["media", "tags"] });
  }, [queryClient]);

  const createMutation = useMutation({
    mutationFn: async (input: Omit<FormState, "id">) =>
      unwrapEnvelope<TagRow>(await api.http.post("/admin/tags", input)),
    onSuccess: invalidateAll,
  });

  const updateMutation = useMutation({
    mutationFn: async ({ id, input }: { id: string; input: Omit<FormState, "id"> }) =>
      unwrapEnvelope<TagRow>(await api.http.put(`/admin/tags/${id}`, input)),
    onSuccess: invalidateAll,
  });

  const deleteMutation = useMutation({
    /** Cùng luồng bulk soft-delete, tránh edge case routing DELETE. */
    mutationFn: async (id: string) =>
      api.http.post("/admin/tags/bulk", {
        action: "delete",
        ids: [String(id).trim()],
      }),
    onSuccess: invalidateAll,
  });

  const restoreMutation = useMutation({
    mutationFn: async (id: string) =>
      unwrapEnvelope<TagRow>(await api.http.post(`/admin/tags/${id}/restore`)),
    onSuccess: invalidateAll,
  });

  const purgeMutation = useMutation({
    mutationFn: async (id: string) => api.http.delete(`/admin/tags/${id}/hard-delete`),
    onSuccess: invalidateAll,
  });

  const bulkMutation = useMutation({
    mutationFn: async (input: {
      action: "delete" | "restore" | "hard-delete";
      ids: string[];
    }) => api.http.post("/admin/tags/bulk", input),
    onSuccess: invalidateAll,
  });

  useEffect(() => {
    setTrashPage(1);
  }, [debouncedTrashQ, trashPageSize]);

  useEffect(() => {
    setListTagSelection({});
    setTrashTagSelection({});
  }, [mainTab]);

  const openCreate = () => {
    setForm(EMPTY_FORM);
    setDialogOpen(true);
  };

  const openEdit = (row: TagRow) => {
    setForm({
      id: row.id,
      name: row.name,
      slug: row.slug,
    });
    setDialogOpen(true);
  };

  const submitting = createMutation.isPending || updateMutation.isPending;

  const handleDelete = useCallback(async (row: TagRow) => {
    await toast.promise(deleteMutation.mutateAsync(row.id), {
      loading: `Đang xóa tạm «${row.name}»...`,
      success: `Đã đưa «${row.name}» vào thùng rác`,
      error: (error: unknown) =>
        error instanceof Error ? error.message : "Không xóa được thẻ",
    });
  }, [deleteMutation]);

  const handleRestore = useCallback(async (row: TagRow) => {
    await toast.promise(restoreMutation.mutateAsync(row.id), {
      loading: `Đang khôi phục «${row.name}»...`,
      success: `Đã khôi phục «${row.name}»`,
      error: (error: unknown) =>
        error instanceof Error ? error.message : "Không khôi phục được thẻ",
    });
  }, [restoreMutation]);

  const handlePurge = useCallback(async (row: TagRow) => {
    await toast.promise(purgeMutation.mutateAsync(row.id), {
      loading: `Đang xóa vĩnh viễn «${row.name}»...`,
      success: `Đã xóa vĩnh viễn «${row.name}»`,
      error: (error: unknown) =>
        error instanceof Error ? error.message : "Không xóa hẳn được thẻ",
    });
  }, [purgeMutation]);

  const handleSave = async () => {
    const payload = {
      name: form.name.trim(),
      slug: form.slug.trim() || slugify(form.name),
    };
    if (!payload.name) {
      toast.error("Vui lòng nhập tên thẻ");
      return;
    }
    try {
      if (form.id) {
        await updateMutation.mutateAsync({ id: form.id, input: payload });
        toast.success(`Đã cập nhật thẻ "${payload.name}"`);
      } else {
        await createMutation.mutateAsync(payload);
        toast.success(`Đã tạo thẻ "${payload.name}"`);
      }
      setDialogOpen(false);
    } catch (error) {
      toast.error(error instanceof Error ? error.message : "Không lưu được thẻ");
    }
  };

  const treeRows = useMemo<TagTreeRow[]>(
    () => buildTagTree(listQuery.data ?? []),
    [listQuery.data],
  );

  const columns = useMemo<ColumnDef<TagTreeRow>[]>(
    () => [
      {
        accessorKey: "name",
        header: "Tên / nhóm",
        cell: ({ row, getValue }) =>
          row.original.isGroup ? (
            <div className="flex items-center gap-2">
              <span className="font-medium capitalize">{String(getValue())}</span>
              <Badge variant="outline" className="text-[10px]">
                {row.original.itemCount} thẻ
              </Badge>
            </div>
          ) : (
            <span className="font-medium">{String(getValue())}</span>
          ),
      },
      {
        accessorKey: "slug",
        header: "Slug",
        cell: ({ row, getValue }) => (
          <span className="font-mono text-xs">
            {row.original.isGroup ? `nhom:${String(getValue())}` : String(getValue())}
          </span>
        ),
      },
      {
        accessorKey: "updatedAt",
        header: "Cập nhật / quy mô",
        cell: ({ row, getValue }) =>
          row.original.isGroup ? (
            <span className="text-xs text-muted-foreground">
              Nhóm theo tiền tố slug
            </span>
          ) : (
            <span className="text-xs text-muted-foreground">
              {formatDateTime(getValue() as string)}
            </span>
          ),
      },
      {
        id: "actions",
        header: "Thao tác",
        enableSorting: false,
        enableColumnFilter: false,
        cell: ({ row }) =>
          row.original.isGroup ? null : (
            <div className="flex flex-wrap gap-1">
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="h-8 gap-1 rounded-lg"
                onClick={() => openEdit(row.original)}
                disabled={!canWrite}
              >
                <Pencil className="size-3.5" />
                Sửa
              </Button>
              <Button
                type="button"
                variant="outline"
                size="sm"
                className="h-8 gap-1 rounded-lg border-destructive/40 text-destructive hover:bg-destructive/10"
                onClick={() => setDeleteTarget(row.original)}
                disabled={!canDelete}
              >
                <Trash2 className="size-3.5" />
                Xóa tạm
              </Button>
            </div>
          ),
      },
    ],
    [canDelete, canWrite],
  );

  const trashColumns = useMemo<ColumnDef<TagRow>[]>(
    () => [
      { accessorKey: "name", header: "Tên" },
      {
        accessorKey: "deletedAt",
        header: "Xóa lúc",
        cell: ({ getValue }) => (
          <span className="text-xs text-muted-foreground">
            {formatDateTime(getValue() as string)}
          </span>
        ),
      },
      {
        id: "actions",
        header: "Thao tác",
        enableSorting: false,
        enableColumnFilter: false,
        cell: ({ row }) => (
          <div className="flex flex-wrap gap-1">
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="h-8 gap-1 rounded-lg"
              onClick={() => setRestoreTarget(row.original)}
              disabled={!canDelete}
            >
              <ArchiveRestore className="size-3.5" />
              Khôi phục
            </Button>
            <Button
              type="button"
              variant="outline"
              size="sm"
              className="h-8 gap-1 rounded-lg border-destructive/40 text-destructive hover:bg-destructive/10"
              onClick={() => setPurgeTarget(row.original)}
              disabled={!canDelete}
            >
              <Trash2 className="size-3.5" />
              Xóa hẳn
            </Button>
          </div>
        ),
      },
    ],
    [canDelete],
  );

  if (!canRead) {
    return (
      <PageSection max="full" className="min-w-0 space-y-6">
        <div className="rounded-lg border border-outline-variant bg-surface-container p-6">
          <TypographyH2 className="text-lg font-semibold">Không có quyền truy cập</TypographyH2>
          <p className="mt-2 text-sm text-muted-foreground">
            Bạn cần quyền <code>tags:view</code> hoặc <code>tags:manage</code> để xem trang này.
          </p>
        </div>
      </PageSection>
    );
  }

  return (
    <PageSection max="full" className="min-w-0 space-y-6">
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <TypographyH1 className={ADMIN_PAGE_TITLE_PRIMARY_CLASS}>
            <Hash className={ADMIN_PAGE_TITLE_ICON_CLASS} aria-hidden />
            Thẻ
          </TypographyH1>
          <p className={ADMIN_PAGE_SUBTITLE_CLASS}>
            Quản lý thẻ dùng chung để gắn cho bài viết và nội dung truyền thông
          </p>
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <Button
            type="button"
            variant="outline"
            className="flex h-12 items-center gap-2 rounded-lg border-outline-variant px-4 font-semibold hover:bg-muted"
            onClick={() => void reload()}
          >
            <RefreshCw
              className={listQuery.isFetching || trashQuery.isFetching ? "size-5 animate-spin" : "size-5"}
            />
            Làm mới
          </Button>
          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger
              render={
                <Button
                  onClick={openCreate}
                  className="flex h-12 items-center gap-2 rounded-lg px-6 font-bold shadow-md"
                  disabled={!canWrite}
                />
              }
            >
              <Plus className="size-5" />
              Thêm thẻ
            </DialogTrigger>
            <DialogContent className={ADMIN_DIALOG_CONTENT_CATEGORY_CLASS}>
              <DialogHeader>
                <DialogTitle className="text-2xl font-extrabold">
                  {form.id ? "Chỉnh sửa thẻ" : "Tạo thẻ mới"}
                </DialogTitle>
                <DialogDescription>
                  Slug được tự động sinh từ tên, phù hợp cho URL hoặc bộ lọc nội dung.
                </DialogDescription>
              </DialogHeader>
              <div className="space-y-4 py-2">
                <div className="space-y-2">
                  <Label htmlFor="tag-name">Tên thẻ</Label>
                  <Input
                    id="tag-name"
                    value={form.name}
                    placeholder="VD: Học bổng"
                    onChange={(e) => {
                      const name = e.target.value;
                      setForm((current) => ({
                        ...current,
                        name,
                        slug: current.id ? current.slug : slugify(name),
                      }));
                    }}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="tag-slug">Slug</Label>
                  <Input
                    id="tag-slug"
                    value={form.slug}
                    placeholder="hoc-bong"
                    onChange={(e) =>
                      setForm((current) => ({
                        ...current,
                        slug: slugify(e.target.value),
                      }))
                    }
                  />
                </div>
              </div>
              <DialogFooter>
                <Button
                  type="button"
                  variant="outline"
                  className="mr-auto rounded-lg"
                  onClick={() => setDialogOpen(false)}
                  disabled={submitting}
                >
                  Hủy
                </Button>
                <Button
                  type="button"
                  className="rounded-lg font-bold"
                  onClick={() => void handleSave()}
                  disabled={!canWrite || submitting}
                >
                  {submitting ? "Đang lưu..." : "Lưu"}
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      <Tabs value={mainTab} onValueChange={(v) => v === "list" || v === "trash" ? setMainTab(v) : null}>
        <TabsList className="h-auto min-h-9 flex-wrap gap-1 rounded-lg p-1">
          <TabsTrigger value="list" className="rounded-lg px-4 py-2 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground">
            Danh sách
          </TabsTrigger>
          <TabsTrigger value="trash" className="rounded-lg px-4 py-2 data-[state=active]:bg-primary data-[state=active]:text-primary-foreground">
            Thùng rác
            {(trashQuery.data?.total ?? 0) > 0 ? (
              <Badge variant="secondary" className="ml-2 px-1.5 py-0 text-[10px] tabular-nums">
                {trashQuery.data?.total}
              </Badge>
            ) : null}
          </TabsTrigger>
        </TabsList>

        <TabsContent value="list" className="mt-4 space-y-4">
          <div className="rounded-lg border border-outline-variant bg-surface-container-low p-4 shadow-sm">
            <p className="text-sm text-muted-foreground">
              Bảng tree của thẻ đang nhóm theo tiền tố slug gần nhất để dễ duyệt nội dung.
              API hiện chưa có quan hệ cha-con thật cho `tag`, nên các nhóm này chỉ là lớp hiển thị.
            </p>
          </div>
          {listQuery.error ? (
            <div className="rounded-lg border border-destructive/30 bg-destructive/5 p-4 text-destructive">
              <div className="flex items-start gap-3">
                <AlertCircle className="mt-0.5 size-5 shrink-0" />
                <div>
                  <p className="font-semibold">Không tải được danh sách thẻ</p>
                  <p className="mt-1 text-sm opacity-90">{listQuery.error.message}</p>
                </div>
              </div>
            </div>
          ) : null}

          <AdminDataTable<TagTreeRow>
            data={treeRows}
            getRowId={(row) => row.id}
            columns={columns}
            isLoading={listQuery.isLoading}
            emptyLabel='Chưa có thẻ — bấm "Thêm thẻ".'
            getSubRows={(row) => row.subRows}
            defaultExpandedAll
            getGlobalFilterText={(row) => `${row.name} ${row.slug}`}
            globalFilter={globalFilter}
            onGlobalFilterChange={setGlobalFilter}
            globalFilterPlaceholder="Tìm theo tên nhóm, tên thẻ hoặc slug..."
            csvExport={{ fileName: "the-dang-hoat-dong.csv" }}
            rowSelectionEnabled={canDelete}
            selectedRowIds={listTagSelection}
            onSelectedRowIdsChange={setListTagSelection}
            canSelectRow={(row) => !row.original.isGroup}
            bulkActions={
              canDelete
                ? [
                    {
                      id: "bulk-tag-delete",
                      label: "Xóa tạm đã chọn",
                      variant: "outline",
                      className: "border-destructive/40 text-destructive",
                      onAction: async (rows) => {
                        const ids = rows.filter((r) => !r.isGroup).map((r) => r.id);
                        if (!ids.length) return;
                        await bulkMutation.mutateAsync({ action: "delete", ids });
                        toast.success(`Đã đưa ${ids.length} thẻ vào thùng rác`);
                      },
                    },
                  ]
                : []
            }
          />
        </TabsContent>

        <TabsContent value="trash" className="mt-4 space-y-4">
          <AdminDataTable<TagRow>
            data={trashQuery.data?.items ?? []}
            getRowId={(row) => row.id}
            columns={trashColumns}
            isLoading={trashQuery.isLoading}
            emptyLabel="Thùng rác trống."
            manualFiltering
            globalFilter={trashGlobalFilter}
            onGlobalFilterChange={setTrashGlobalFilter}
            globalFilterPlaceholder="Tìm trong thùng rác..."
            csvExport={{ fileName: "the-thung-rac.csv" }}
            rowSelectionEnabled={canDelete}
            selectedRowIds={trashTagSelection}
            onSelectedRowIdsChange={setTrashTagSelection}
            bulkActions={
              canDelete
                ? [
                    {
                      id: "bulk-tag-restore",
                      label: "Khôi phục đã chọn",
                      onAction: async (rows) => {
                        const ids = rows.map((r) => r.id);
                        if (!ids.length) return;
                        await bulkMutation.mutateAsync({ action: "restore", ids });
                        toast.success(`Đã khôi phục ${ids.length} thẻ`);
                      },
                    },
                    {
                      id: "bulk-tag-purge",
                      label: "Xóa vĩnh viễn đã chọn",
                      variant: "outline",
                      className: "border-destructive/40 text-destructive",
                      onAction: async (rows) => {
                        const ids = rows.map((r) => r.id);
                        if (!ids.length) return;
                        await bulkMutation.mutateAsync({ action: "hard-delete", ids });
                        toast.success(`Đã xóa vĩnh viễn ${ids.length} thẻ`);
                      },
                    },
                  ]
                : []
            }
            footer={
              <AdminTablePaginationFooter
                page={trashPage}
                pageSize={trashPageSize}
                total={trashQuery.data?.total ?? 0}
                isLoading={trashQuery.isLoading}
                onPageChange={setTrashPage}
                onPageSizeChange={setTrashPageSize}
                emptySummary="Không có thẻ trong thùng rác"
                itemLabel="thẻ"
              />
            }
          />
        </TabsContent>
      </Tabs>

      <AdminConfirmActionDialog
        open={deleteTarget != null}
        onOpenChange={(open) => {
          if (!open) setDeleteTarget(null);
        }}
        contentClassName={ADMIN_ALERT_DIALOG_CONTENT_CLASS}
        icon={<Trash2 className="size-5 shrink-0 text-destructive" />}
        title="Đưa thẻ vào thùng rác?"
        description={
          deleteTarget ? (
            <>
              Thẻ <strong className="text-foreground">{deleteTarget.name}</strong> (slug{" "}
              <span className="font-mono">{deleteTarget.slug}</span>) sẽ được ẩn khỏi danh sách
              đang dùng.
            </>
          ) : null
        }
        confirmLabel="Xóa tạm"
        confirmDestructive
        onConfirm={() => {
          if (!deleteTarget) return;
          void handleDelete(deleteTarget).finally(() => setDeleteTarget(null));
        }}
      />

      <AdminConfirmActionDialog
        open={restoreTarget != null}
        onOpenChange={(open) => {
          if (!open) setRestoreTarget(null);
        }}
        contentClassName={ADMIN_ALERT_DIALOG_CONTENT_CLASS}
        icon={<ArchiveRestore className="size-5 shrink-0 text-primary" />}
        title="Khôi phục thẻ?"
        description={
          restoreTarget ? (
            <>
              Đưa thẻ <strong className="text-foreground">{restoreTarget.name}</strong> trở lại danh
              sách hoạt động.
            </>
          ) : null
        }
        confirmLabel="Khôi phục"
        onConfirm={() => {
          if (!restoreTarget) return;
          void handleRestore(restoreTarget).finally(() => setRestoreTarget(null));
        }}
      />

      <AdminConfirmActionDialog
        open={purgeTarget != null}
        onOpenChange={(open) => {
          if (!open) setPurgeTarget(null);
        }}
        contentClassName={ADMIN_ALERT_DIALOG_CONTENT_CLASS}
        titleClassName="flex items-center gap-2 text-left text-destructive"
        icon={<Trash2 className="size-5 shrink-0" />}
        title="Xóa vĩnh viễn thẻ?"
        description={
          purgeTarget ? (
            <>
              Thẻ <strong className="text-foreground">{purgeTarget.name}</strong> sẽ bị xóa khỏi hệ
              thống và không thể hoàn tác.
            </>
          ) : null
        }
        confirmLabel="Xóa vĩnh viễn"
        confirmDestructive
        onConfirm={() => {
          if (!purgeTarget) return;
          void handlePurge(purgeTarget).finally(() => setPurgeTarget(null));
        }}
      />
    </PageSection>
  );
}

export default function TagsPage() {
  return (
    <AdminPageGuard roles={["super_admin", "admin", "manager"]}>
      <TagsPageInner />
    </AdminPageGuard>
  );
}

src/components/admin-confirm-action-dial.content:
"use client";

import type { ReactNode } from "react";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@ui/components/alert-dialog";
import { Loader2 } from "lucide-react";

type AdminConfirmActionDialogProps = {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  title: string;
  description?: ReactNode;
  icon?: ReactNode;
  confirmLabel: string;
  cancelLabel?: string;
  confirmDestructive?: boolean;
  confirmDisabled?: boolean;
  confirmLoading?: boolean;
  onConfirm: () => void;
  contentClassName?: string;
  footerClassName?: string;
  titleClassName?: string;
};

export function AdminConfirmActionDialog({
  open,
  onOpenChange,
  title,
  description,
  icon,
  confirmLabel,
  cancelLabel = "Huỷ",
  confirmDestructive = false,
  confirmDisabled = false,
  confirmLoading = false,
  onConfirm,
  contentClassName,
  footerClassName,
  titleClassName,
}: AdminConfirmActionDialogProps) {
  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent className={contentClassName}>
        <AlertDialogHeader>
          <AlertDialogTitle className={titleClassName ?? "flex items-center gap-2 text-left"}>
            {icon}
            {title}
          </AlertDialogTitle>
          {description ? <AlertDialogDescription>{description}</AlertDialogDescription> : null}
        </AlertDialogHeader>
        <AlertDialogFooter className={footerClassName}>
          <AlertDialogCancel className="rounded-lg">{cancelLabel}</AlertDialogCancel>
          <AlertDialogAction
            className={
              confirmDestructive
                ? "rounded-lg bg-destructive text-destructive-foreground hover:bg-destructive/90"
                : "rounded-lg"
            }
            onClick={(event) => {
              event.preventDefault();
              onConfirm();
            }}
            disabled={confirmDisabled}
          >
            {confirmLoading ? <Loader2 className="size-4 animate-spin" /> : confirmLabel}
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

src/components/admin-data-table/admin-da.content:
"use client";

import {
  flexRender,
  getCoreRowModel,
  getExpandedRowModel,
  getFilteredRowModel,
  getSortedRowModel,
  useReactTable,
  type ColumnDef,
  type ColumnFiltersState,
  type ExpandedState,
  type Header,
  type OnChangeFn,
  type RowSelectionState,
  type Row,
  type SortingState,
} from "@tanstack/react-table";
import { ChevronDown, ChevronRight, Download } from "lucide-react";
import { useCallback, useMemo, useState, type ReactNode } from "react";
import { Button } from "@ui/components/button";
import { Checkbox } from "@ui/components/checkbox";
import { Input } from "@ui/components/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@ui/components/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@ui/components/table";
import { cn } from "@ui/lib/utils";
import "@/components/admin-data-table/table-meta";
import { buildCsvFromColumns } from "@/lib/build-table-csv";
import { downloadCsvFile } from "@/lib/export-csv";
import {
  csvBaseToXlsxFilename,
  downloadXlsxFile,
} from "@/lib/export-xlsx";
import { Separator } from "@ui/components/separator";
import { TypographyPSmall } from "@ui/components/typography";

const ALL_SELECT = "__all__";

export type AdminDataTableBulkAction<TData> = {
  id: string;
  label: string;
  onAction: (selectedRows: TData[]) => void | Promise<void>;
  icon?: ReactNode;
  variant?: "default" | "destructive" | "outline" | "secondary" | "ghost" | "link";
  className?: string;
  requiresSelection?: boolean;
  clearSelectionOnSuccess?: boolean;
  disabled?: (selectedRows: TData[]) => boolean;
};

export type AdminDataTableProps<TData> = {
  data: TData[];
  columns: ColumnDef<TData, unknown>[];
  getSubRows?: (row: TData) => TData[] | undefined;
  getRowId?: (originalRow: TData, index: number, parent?: Row<TData>) => string;
  isLoading?: boolean;
  emptyLabel?: string;
  /** Mở toàn bộ nhánh cây lúc đầu */
  defaultExpandedAll?: boolean;
  getRowClassName?: (row: Row<TData>) => string | undefined;
  /** Ô tìm nhanh (chuỗi do bạn cung cấp cho mỗi dòng) */
  getGlobalFilterText?: (row: TData) => string;
  globalFilterPlaceholder?: string;
  /** Bật khi lọc do API/server — chỉ giữ state ô lọc, không lọc lại `data` trên client */
  manualFiltering?: boolean;
  columnFilters?: ColumnFiltersState;
  onColumnFiltersChange?: OnChangeFn<ColumnFiltersState>;
  globalFilter?: string;
  onGlobalFilterChange?: OnChangeFn<string>;
  /** Nút / nhóm tùy chọn cạnh ô tìm nhanh (vd. “Xóa bộ lọc”) */
  filterToolbarExtra?: ReactNode;
  /** Phân trang / tóm tắt ngay dưới bảng */
  footer?: ReactNode;
  /**
   * Hiện nút xuất CSV + Excel (dữ liệu đúng mảng `data` hiện tại — thường là một trang/lớp đã lọc).
   */
  csvExport?: boolean | { fileName?: string; sheetName?: string };
  /** Bật cột chọn dòng cho thao tác hàng loạt */
  rowSelectionEnabled?: boolean;
  /** Kiểm soát dòng nào được phép tick */
  canSelectRow?: (row: Row<TData>) => boolean;
  selectedRowIds?: RowSelectionState;
  onSelectedRowIdsChange?: OnChangeFn<RowSelectionState>;
  bulkActions?: AdminDataTableBulkAction<TData>[];
};

function includesText(a: unknown, q: string): boolean {
  if (!q) return true;
  const s = String(a ?? "").toLowerCase();
  return s.includes(q.toLowerCase());
}

function columnFilterToolbarLabel<TData>(
  header: Header<TData, unknown>,
): string {
  const meta = header.column.columnDef.meta;
  if (meta?.filterLabel) return meta.filterLabel;
  const h = header.column.columnDef.header;
  if (typeof h === "string") return h;
  return header.column.id;
}

export function AdminDataTable<TData>({
  data,
  columns,
  getSubRows,
  isLoading,
  emptyLabel = "Không có dữ liệu",
  defaultExpandedAll = true,
  getRowClassName,
  getGlobalFilterText,
  globalFilterPlaceholder = "Tìm trong bảng…",
  manualFiltering = false,
  columnFilters: columnFiltersControlled,
  onColumnFiltersChange,
  globalFilter: globalFilterControlled,
  onGlobalFilterChange,
  filterToolbarExtra,
  footer,
  csvExport,
  rowSelectionEnabled = false,
  canSelectRow,
  getRowId,
  selectedRowIds: selectedRowIdsControlled,
  onSelectedRowIdsChange,
  bulkActions = [],
}: AdminDataTableProps<TData>) {
  const [sorting, setSorting] = useState<SortingState>([]);
  const [columnFiltersInternal, setColumnFiltersInternal] =
    useState<ColumnFiltersState>([]);
  const [globalFilterInternal, setGlobalFilterInternal] = useState("");
  const [selectedRowIdsInternal, setSelectedRowIdsInternal] = useState<RowSelectionState>({});
  const [runningBulkActionId, setRunningBulkActionId] = useState<string | null>(null);
  const columnFilters = columnFiltersControlled ?? columnFiltersInternal;
  const setColumnFilters =
    onColumnFiltersChange ?? setColumnFiltersInternal;
  const globalFilter = globalFilterControlled ?? globalFilterInternal;
  const setGlobalFilter = onGlobalFilterChange ?? setGlobalFilterInternal;
  const selectedRowIds = selectedRowIdsControlled ?? selectedRowIdsInternal;
  const setSelectedRowIds = onSelectedRowIdsChange ?? setSelectedRowIdsInternal;
  const showGlobalFilter =
    getGlobalFilterText != null || onGlobalFilterChange != null;
  const csvExportEnabled = Boolean(csvExport);
  const hasBulkActions = bulkActions.length > 0;
  const exportFileNameProp =
    typeof csvExport === "object" && csvExport != null
      ? csvExport.fileName?.trim()
      : undefined;
  const exportSheetNameProp =
    typeof csvExport === "object" && csvExport != null
      ? csvExport.sheetName?.trim()
      : undefined;
  const resolvedCsvFileName = useMemo(() => {
    if (exportFileNameProp) {
      return exportFileNameProp.toLowerCase().endsWith(".csv")
        ? exportFileNameProp
        : `${exportFileNameProp}.csv`;
    }
    return `xuat-bang-${new Date().toISOString().slice(0, 10)}.csv`;
  }, [exportFileNameProp]);
  const resolvedXlsxFileName = useMemo(
    () => csvBaseToXlsxFilename(resolvedCsvFileName),
    [resolvedCsvFileName],
  );

  const handleCsvExport = useCallback(() => {
    const { headers, rows } = buildCsvFromColumns(data, columns);
    downloadCsvFile(resolvedCsvFileName, headers, rows);
  }, [columns, data, resolvedCsvFileName]);

  const handleXlsxExport = useCallback(() => {
    const { headers, rows } = buildCsvFromColumns(data, columns);
    void downloadXlsxFile(
      resolvedXlsxFileName,
      headers,
      rows,
      exportSheetNameProp || "Dữ liệu",
    );
  }, [columns, data, exportSheetNameProp, resolvedXlsxFileName]);
  const [expanded, setExpanded] = useState<ExpandedState>(
    defaultExpandedAll ? true : {},
  );

  const expanderColumn = useMemo<ColumnDef<TData, unknown>>(
    () => ({
      id: "_expand",
      header: () => null,
      cell: ({ row }) => {
        if (!row.getCanExpand()) {
          return <span className="inline-block w-8 shrink-0" aria-hidden />;
        }
        return (
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className="h-8 w-8 shrink-0"
            aria-expanded={row.getIsExpanded()}
            aria-label={row.getIsExpanded() ? "Thu gọn" : "Mở rộng"}
            onClick={(e) => {
              e.stopPropagation();
              row.getToggleExpandedHandler()();
            }}
          >
            {row.getIsExpanded() ? (
              <ChevronDown className="size-4" />
            ) : (
              <ChevronRight className="size-4" />
            )}
          </Button>
        );
      },
      enableSorting: false,
      enableColumnFilter: false,
      meta: { disableColumnFilter: true },
      size: 44,
    }),
    [],
  );

  const selectionColumn = useMemo<ColumnDef<TData, unknown>>(
    () => ({
      id: "_select",
      header: ({ table }) => (
        <Checkbox
          checked={table.getIsAllPageRowsSelected()}
          indeterminate={
            !table.getIsAllPageRowsSelected() && table.getIsSomePageRowsSelected()
          }
          onCheckedChange={(value) => table.toggleAllPageRowsSelected(value === true)}
          aria-label="Chọn tất cả dòng"
        />
      ),
      cell: ({ row }) => (
        <Checkbox
          checked={row.getIsSelected()}
          onCheckedChange={(value) => row.toggleSelected(value === true)}
          disabled={!row.getCanSelect()}
          aria-label="Chọn dòng"
        />
      ),
      enableSorting: false,
      enableColumnFilter: false,
      meta: { disableColumnFilter: true },
      size: 44,
    }),
    [],
  );

  const tableColumns = useMemo(
    () => {
      const built: ColumnDef<TData, unknown>[] = [];
      if (rowSelectionEnabled) built.push(selectionColumn);
      if (getSubRows) built.push(expanderColumn);
      built.push(...columns);
      return built;
    },
    [columns, expanderColumn, getSubRows, rowSelectionEnabled, selectionColumn],
  );

  const table = useReactTable({
    data,
    columns: tableColumns,
    state: {
      sorting,
      columnFilters,
      globalFilter,
      expanded,
      rowSelection: selectedRowIds,
    },
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onGlobalFilterChange: setGlobalFilter,
    onExpandedChange: setExpanded,
    onRowSelectionChange: setSelectedRowIds,
    getSubRows,
    getRowId,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getExpandedRowModel: getExpandedRowModel(),
    manualFiltering,
    // false: lọc từ dòng cha xuống (đúng cho cây SP→đơn vị). true + filterFn “luôn pass” ở lá
    // khiến cha luôn được giữ vì còn lá con → lọc cột như không chạy.
    filterFromLeafRows: false,
    globalFilterFn: manualFiltering
      ? "includesString"
      : getGlobalFilterText
        ? (row, _columnId, filterValue) => {
            const q = String(filterValue ?? "").trim();
            if (!q) return true;
            return includesText(getGlobalFilterText(row.original), q);
          }
        : "includesString",
    autoResetExpanded: false,
    defaultColumn: {
      enableColumnFilter: true,
      filterFn: (row, columnId, filterValue) => {
        if (filterValue == null || filterValue === "") return true;
        return includesText(row.getValue(columnId), String(filterValue));
      },
    },
    enableRowSelection: rowSelectionEnabled
      ? (row) => (canSelectRow ? canSelectRow(row) : true)
      : false,
  });

  const headerGroups = table.getHeaderGroups();
  const rows = table.getRowModel().rows;
  const selectedRows = table.getSelectedRowModel().rows.map((row) => row.original);
  const selectedCount = selectedRows.length;

  const runBulkAction = useCallback(
    async (action: AdminDataTableBulkAction<TData>) => {
      if (runningBulkActionId != null) return;
      const requiresSelection = action.requiresSelection ?? true;
      if (requiresSelection && selectedRows.length === 0) return;
      if (action.disabled?.(selectedRows)) return;
      setRunningBulkActionId(action.id);
      try {
        await action.onAction(selectedRows);
        if (action.clearSelectionOnSuccess ?? true) {
          table.resetRowSelection();
        }
      } finally {
        setRunningBulkActionId(null);
      }
    },
    [runningBulkActionId, selectedRows, table],
  );

  const filterableHeaders = table
    .getFlatHeaders()
    .filter(
      (h) =>
        h.column.getCanFilter() &&
        !h.column.columnDef.meta?.disableColumnFilter,
    );

  function renderOutsideColumnFilter(header: Header<TData, unknown>) {
    const col = header.column;
    const controlId = `admin-col-filter-ctl-${header.id}`;
    const meta = col.columnDef.meta;
    const variant = meta?.filterVariant ?? "text";
    const ph = meta?.filterPlaceholder ?? "Lọc…";

    if (variant === "select" && meta?.selectOptions?.length) {
      const opts = meta.selectOptions;
      const v = (col.getFilterValue() as string) ?? ALL_SELECT;
      return (
        <Select
          value={v === "" || v == null ? ALL_SELECT : v}
          onValueChange={(next) =>
            col.setFilterValue(next === ALL_SELECT ? undefined : next)
          }
        >
          <SelectTrigger
            id={controlId}
            className="h-9 text-sm rounded-lg w-full min-w-[160px]"
          >
            <SelectValue placeholder="Tất cả">
              {v === ALL_SELECT ? "Tất cả" : undefined}
            </SelectValue>
          </SelectTrigger>
          <SelectContent className="max-h-[min(60vh,22rem)] overflow-y-auto">
            <SelectItem value={ALL_SELECT}>Tất cả</SelectItem>
            {opts.map((o) => (
              <SelectItem key={o.value} value={o.value}>
                {o.label}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      );
    }

    if (variant === "number") {
      return (
        <Input
          id={controlId}
          type="number"
          className="h-9 text-sm rounded-lg"
          placeholder={ph}
          value={(col.getFilterValue() as string) ?? ""}
          onChange={(e) =>
            col.setFilterValue(
              e.target.value === "" ? undefined : Number(e.target.value),
            )
          }
        />
      );
    }

    return (
      <Input
        id={controlId}
        className="h-9 text-sm rounded-lg"
        placeholder={ph}
        value={(col.getFilterValue() as string) ?? ""}
        onChange={(e) =>
          col.setFilterValue(e.target.value === "" ? undefined : e.target.value)
        }
      />
    );
  }

  if (isLoading) {
    return (
      <div className="space-y-2 rounded-lg border border-border bg-card p-4">
        {Array.from({ length: 6 }).map((_, i) => (
          <div
            key={i}
            className="h-10 rounded-md bg-muted/40 animate-pulse"
          />
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-3">
      {(showGlobalFilter ||
        filterableHeaders.length > 0 ||
        filterToolbarExtra ||
        csvExportEnabled ||
        (rowSelectionEnabled && hasBulkActions)) && (
        <div className="rounded-lg border border-border bg-card p-3 sm:p-4 space-y-4">
          {showGlobalFilter || filterToolbarExtra || csvExportEnabled ? (
            <div className="flex flex-wrap items-end gap-3">
              {showGlobalFilter ? (
                <div className="flex min-w-[min(100%,18rem)] flex-1 flex-col gap-1.5">
                  <label className="text-xs font-semibold text-muted-foreground">
                    Tìm nhanh
                  </label>
                  <Input
                    placeholder={globalFilterPlaceholder}
                    value={globalFilter}
                    onChange={(e) => setGlobalFilter(e.target.value)}
                    className="bg-background rounded-lg w-full"
                  />
                </div>
              ) : null}
              <div className="flex flex-wrap items-end gap-2 shrink-0">
                {csvExportEnabled ? (
                  <div className="flex flex-col gap-1.5">
                    <span className="text-xs font-semibold text-muted-foreground">
                      Xuất file
                    </span>
                    <div className="flex flex-wrap gap-2">
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        className="h-9 gap-1.5 rounded-lg"
                        disabled={data.length === 0}
                        onClick={handleCsvExport}
                        title="CSV: cột phân tách bằng ; + UTF-16 LE (Excel VN)"
                      >
                        <Download className="size-4" />
                        CSV
                      </Button>
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        className="h-9 gap-1.5 rounded-lg"
                        disabled={data.length === 0}
                        onClick={handleXlsxExport}
                        title="Excel: cột rộng theo nội dung, Unicode chuẩn"
                      >
                        <Download className="size-4" />
                        Excel
                      </Button>
                    </div>
                  </div>
                ) : null}
                {filterToolbarExtra ? (
                  <div className="flex flex-wrap gap-2">{filterToolbarExtra}</div>
                ) : null}
              </div>
            </div>
          ) : null}
          {rowSelectionEnabled && hasBulkActions ? (
            <div className="flex flex-wrap items-center justify-between gap-3 rounded-lg border border-border/70 bg-muted/20 px-3 py-2">
              <p className="text-xs font-medium text-muted-foreground">
                Đã chọn <span className="font-semibold text-foreground">{selectedCount}</span> dòng
              </p>
              <div className="flex flex-wrap items-center gap-2">
                {bulkActions.map((action) => {
                  const requiresSelection = action.requiresSelection ?? true;
                  const disabledBySelection = requiresSelection && selectedCount === 0;
                  const disabledByAction = action.disabled?.(selectedRows) ?? false;
                  const isRunning = runningBulkActionId === action.id;
                  return (
                    <Button
                      key={action.id}
                      type="button"
                      size="sm"
                      variant={action.variant ?? "outline"}
                      className={cn("h-8 gap-1.5 rounded-lg", action.className)}
                      disabled={
                        isRunning ||
                        runningBulkActionId != null ||
                        disabledBySelection ||
                        disabledByAction
                      }
                      onClick={() => {
                        void runBulkAction(action);
                      }}
                    >
                      {action.icon}
                      {action.label}
                    </Button>
                  );
                })}
              </div>
            </div>
          ) : null}
          {filterableHeaders.length > 0 && (
            <div className="space-y-2">
              <Separator />
              <TypographyPSmall className="font-semibold">
                Lọc theo cột
              </TypographyPSmall>
              <div className="flex flex-wrap gap-x-4 gap-y-3 items-end">
                {filterableHeaders.map((header) => (
                  <div
                    key={header.id}
                    className="flex flex-col gap-1 min-w-[min(100%,12rem)] w-[12rem]"
                  >
                    <label
                      htmlFor={`admin-col-filter-ctl-${header.id}`}
                      className="text-xs font-medium text-foreground/80"
                    >
                      {columnFilterToolbarLabel(header)}
                    </label>
                    <div>{renderOutsideColumnFilter(header)}</div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      <div className="rounded-lg border border-border bg-card overflow-hidden">
        <div className="overflow-x-auto pt-2">
        <Table className="text-sm min-w-[640px] sm:min-w-0">
          <TableHeader>
            {headerGroups.map((hg) => (
              <TableRow key={hg.id} className="hover:bg-transparent">
                {hg.headers.map((header) => (
                  <TableHead
                    key={header.id}
                    className={cn(
                      "align-top font-semibold whitespace-normal",
                      header.column.getCanSort() && "cursor-pointer select-none",
                    )}
                    onClick={header.column.getToggleSortingHandler()}
                  >
                    {header.isPlaceholder ? null : (
                      <div className="flex flex-col gap-1 py-1">
                        <span className="flex items-center gap-1">
                          {flexRender(
                            header.column.columnDef.header,
                            header.getContext(),
                          )}
                          {header.column.getIsSorted() === "asc"
                            ? " ↑"
                            : header.column.getIsSorted() === "desc"
                              ? " ↓"
                              : null}
                        </span>
                      </div>
                    )}
                  </TableHead>
                ))}
              </TableRow>
            ))}
          </TableHeader>
          <TableBody>
            {rows.length === 0 ? (
              <TableRow>
                <TableCell
                  colSpan={tableColumns.length}
                  className="h-24 text-center text-muted-foreground"
                >
                  {emptyLabel}
                </TableCell>
              </TableRow>
            ) : (
              rows.map((row) => (
                <TableRow
                  key={row.id}
                  data-depth={row.depth}
                  className={cn(
                    row.depth > 0 && "bg-muted/15",
                    getRowClassName?.(row),
                  )}
                >
                  {row.getVisibleCells().map((cell) => {
                    const colIndex = cell.column.getIndex();
                    const indent =
                      getSubRows && colIndex === 1 ? row.depth * 14 : 0;
                    return (
                      <TableCell
                        key={cell.id}
                        className="whitespace-normal align-middle max-w-[min(420px,40vw)]"
                        style={{
                          paddingLeft:
                            indent > 0
                              ? `calc(0.5rem + ${indent}px)`
                              : undefined,
                        }}
                      >
                        {flexRender(
                          cell.column.columnDef.cell,
                          cell.getContext(),
                        )}
                      </TableCell>
                    );
                  })}
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
        </div>
      </div>
      {footer ? (
        <div className="flex flex-wrap items-center justify-between gap-3 rounded-lg border border-border bg-card px-3 py-3 sm:px-4">
          {footer}
        </div>
      ) : null}
    </div>
  );
}

