import { createStoreSyncSdk, DEFAULT_API_URL } from "@workspace/api-client";
import { getAdminDevAuthLogContext, getAdminUserId } from "./auth-session";

/**
 * Single SDK instance shared across the admin panel.
 * `X-User-Id` lấy từ phiên đăng nhập (sessionStorage) để RBAC trên API khớp.
 */
export const api = createStoreSyncSdk({
  baseUrl: process.env.NEXT_PUBLIC_API_URL ?? DEFAULT_API_URL,
  getUserId: () => {
    if (typeof window === "undefined") return null;
    return getAdminUserId();
  },
  // Bắt buộc bật rõ: trong browser không có globalThis.process nên api-client
  // không tự nhận NODE_ENV; Next vẫn inline process.env.NODE_ENV ở đây.
  devLogging: process.env.NODE_ENV === "development",
  devLogTag: "storesync-admin",
  getDevAuthContext: () => getAdminDevAuthLogContext(),
});

export type {
  AuthUser,
  ChangePasswordInput,
  CreateUserInput,
  RbacPermission,
  RbacRole,
  User,
  UserRoleRef,
  Category,
  CategoryUsage,
  CreateCategoryInput,
  UpdateCategoryInput,
  UpdateProfileInput,
  UpdateUserInput,
} from "@workspace/api-client";
export { ApiError } from "@workspace/api-client";

src/lib/auth-routes.ts.content:
/**
 * Các đường dẫn “công khai” — không bọc sidebar, không yêu cầu phiên.
 * Đã đăng nhập hợp lệ (staff) sẽ bị chuyển về dashboard.
 */
export const AUTH_LOGIN_PATH = "/login";
export const AUTH_REGISTER_PATH = "/register";

export const AUTH_PATHS = [
  AUTH_LOGIN_PATH,
  AUTH_REGISTER_PATH,
] as const;

export type AuthPath = (typeof AUTH_PATHS)[number];

const AUTH_SET = new Set<string>(AUTH_PATHS);

export function isAuthPath(pathname: string | null | undefined): boolean {
  if (!pathname) return false;
  return AUTH_SET.has(pathname);
}

function inferExternalAdminBase(pathname: string | null | undefined): string {
  if (!pathname) return "";
  const normalized = pathname.replace(/\/+$/, "") || "/";
  if (normalized === "/admin" || normalized.startsWith("/admin/")) {
    return "/admin";
  }
  return "";
}

export function getAdminAppHomeExternalPath(
  pathname: string | null | undefined = typeof window !== "undefined"
    ? window.location.pathname
    : undefined,
): string {
  const base = inferExternalAdminBase(pathname);
  return base || "/";
}

export function getAdminLoginExternalPath(
  pathname: string | null | undefined = typeof window !== "undefined"
    ? window.location.pathname
    : undefined,
): string {
  const base = inferExternalAdminBase(pathname);
  return `${base}${AUTH_LOGIN_PATH}`;
}

