function normalizeBasePath(raw: string | undefined): string {
  const v = (raw ?? "").trim();
  if (!v) return "";
  const withSlash = v.startsWith("/") ? v : `/${v}`;
  return withSlash.replace(/\/+$/, "");
}

const basePath = normalizeBasePath(process.env.BACKEND_BASE_PATH);

